import type { CoverageDetailDTO, LintDetailDTO, LintMessageDTO, FileDetailDTO, FileMetric, FileMetricError } from "@/api/endpoints/insights";
import "@/components/features/insights/InsightDetailPanel.css";

type Props = {
  relativePath: string | null;
  detail: FileDetailDTO | undefined;
  isLoading: boolean;
  metricLabels: Record<string, string>;
  onClose: () => void;
};

function timeAgo(iso: string): string {
  const diff = Date.now() - new Date(iso).getTime();
  const mins = Math.floor(diff / 60000);
  if (mins < 1) return "just now";
  if (mins < 60) return `${mins}m ago`;
  const hrs = Math.floor(mins / 60);
  if (hrs < 24) return `${hrs}h ago`;
  return `${Math.floor(hrs / 24)}d ago`;
}

function isMetricError(v: unknown): v is FileMetricError {
  return typeof v === "object" && v !== null && "error" in v;
}

function CoverageBar({ pct }: { pct: number }) {
  const cls =
    pct >= 80
      ? "insight-detail-panel__cov-fill--green"
      : pct >= 50
      ? "insight-detail-panel__cov-fill--amber"
      : "insight-detail-panel__cov-fill--red";
  return (
    <span className="insight-detail-panel__cov-bar">
      <span
        className={`insight-detail-panel__cov-fill ${cls}`}
        style={{ width: `${pct}%` }}
      />
    </span>
  );
}

function CoverageSection({ coverage }: { coverage: CoverageDetailDTO }) {
  const rows: [string, { pct: number }][] = [
    ["Lines", coverage.lines],
    ["Branches", coverage.branches],
    ["Functions", coverage.functions],
    ["Statements", coverage.statements],
  ];
  return (
    <div className="insight-detail-panel__section">
      <div className="insight-detail-panel__section-header">
        <span>Coverage</span>
        <span className="insight-detail-panel__section-age">
          {timeAgo(coverage.reportedAt)}
        </span>
      </div>
      <div className="insight-detail-panel__cov-grid">
        {rows.map(([label, stat]) => (
          <div key={label} className="insight-detail-panel__cov-row">
            <span className="insight-detail-panel__cov-label">{label}</span>
            <CoverageBar pct={stat.pct} />
            <span className="insight-detail-panel__cov-pct">{stat.pct}%</span>
          </div>
        ))}
      </div>
    </div>
  );
}

function LintSection({ lint }: { lint: LintDetailDTO }) {
  return (
    <div className="insight-detail-panel__section">
      <div className="insight-detail-panel__section-header">
        <span>
          Lint
          {lint.errors > 0 && (
            <span className="insight-detail-panel__lint-badge insight-detail-panel__lint-badge--error">
              {lint.errors} error{lint.errors !== 1 ? "s" : ""}
            </span>
          )}
          {lint.warnings > 0 && (
            <span className="insight-detail-panel__lint-badge insight-detail-panel__lint-badge--warn">
              {lint.warnings} warning{lint.warnings !== 1 ? "s" : ""}
            </span>
          )}
          {lint.errors === 0 && lint.warnings === 0 && (
            <span className="insight-detail-panel__lint-badge insight-detail-panel__lint-badge--ok">
              clean
            </span>
          )}
        </span>
        <span className="insight-detail-panel__section-age">
          {timeAgo(lint.reportedAt)}
        </span>
      </div>
      {lint.messages.length > 0 && (
        <div className="insight-detail-panel__lint-messages">
          {lint.messages.map((m: LintMessageDTO, i: number) => (
            <div
              key={i}
              className={`insight-detail-panel__lint-msg${m.severity === 2 ? " insight-detail-panel__lint-msg--error" : " insight-detail-panel__lint-msg--warn"}`}
            >
              <span className="insight-detail-panel__lint-loc">
                {m.line}:{m.column}
              </span>
              <span className="insight-detail-panel__lint-text">{m.message}</span>
              {m.ruleId && (
                <span className="insight-detail-panel__lint-rule">{m.ruleId}</span>
              )}
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

export function InsightDetailPanel({
  relativePath,
  detail,
  isLoading,
  metricLabels,
  onClose,
}: Props) {
  if (!relativePath) {
    return (
      <div className="insight-detail-panel">
        <div className="insight-detail-panel__empty">Select a file to view details</div>
      </div>
    );
  }

  const parts = relativePath.split("/");
  const name = parts[parts.length - 1] ?? relativePath;

  return (
    <div className="insight-detail-panel">
      <div className="insight-detail-panel__header">
        <span className="insight-detail-panel__filename">{name}</span>
        <span className="insight-detail-panel__path">{relativePath}</span>
        <button className="insight-detail-panel__close" onClick={onClose} aria-label="Close">
          ✕
        </button>
      </div>

      {isLoading && (
        <div className="insight-detail-panel__loading">Loading…</div>
      )}

      {!isLoading && detail && (
        <div className="insight-detail-panel__body">
          {/* LLM metrics */}
          <div className="insight-detail-panel__section">
            <div className="insight-detail-panel__section-header">
              <span>Analysis</span>
            </div>
            <div className="insight-detail-panel__metrics">
              {Object.entries(metricLabels).map(([name, label]) => {
                const v = detail.metrics[name];
                let statusClass = "insight-detail-panel__metric--unrun";
                let statusText = "Not analysed";
                let summary = "";

                if (v === "pending") {
                  statusClass = "insight-detail-panel__metric--pending";
                  statusText = "Analysing…";
                } else if (v === null) {
                  statusClass = "insight-detail-panel__metric--error";
                  statusText = "Failed";
                } else if (isMetricError(v)) {
                  statusClass = "insight-detail-panel__metric--error";
                  statusText = "Failed";
                  summary = v.error;
                } else if (v !== undefined) {
                  const m = v as FileMetric;
                  statusClass = `insight-detail-panel__metric--${m.status}`;
                  statusText = m.status;
                  summary = m.summary;
                }

                return (
                  <div key={name} className={`insight-detail-panel__metric ${statusClass}`}>
                    <div className="insight-detail-panel__metric-header">
                      <span className="insight-detail-panel__metric-dot" />
                      <span className="insight-detail-panel__metric-label">{label}</span>
                      <span className="insight-detail-panel__metric-status">{statusText}</span>
                    </div>
                    {summary && (
                      <p className="insight-detail-panel__metric-summary">{summary}</p>
                    )}
                  </div>
                );
              })}
            </div>
          </div>

          {detail.coverage && <CoverageSection coverage={detail.coverage} />}
          {!detail.coverage && (
            <div className="insight-detail-panel__section">
              <div className="insight-detail-panel__section-header">
                <span>Coverage</span>
                <span className="insight-detail-panel__unavailable">not found</span>
              </div>
            </div>
          )}

          {detail.lint && <LintSection lint={detail.lint} />}
          {!detail.lint && (
            <div className="insight-detail-panel__section">
              <div className="insight-detail-panel__section-header">
                <span>Lint</span>
                <span className="insight-detail-panel__unavailable">not found</span>
              </div>
            </div>
          )}
        </div>
      )}
    </div>
  );
}

import { useState, useEffect, useMemo } from "react";
import type { FileSnapshotDTO } from "@/api/endpoints/insights";
import { MetricBadge } from "@/components/features/insights/MetricBadge";
import "@/components/features/insights/InsightTreeTable.css";

// ─── Tree data structures ───────────────────────────────────────────────────

interface FolderNode {
  kind: "folder";
  name: string;
  path: string;
  childFolders: FolderNode[];
  files: FileSnapshotDTO[];
}

interface FolderStats {
  fileCount: number;
  totalLines: number;
  metricCounts: Record<
    string,
    { green: number; amber: number; red: number; error: number; pending: number; unrun: number }
  >;
}

// ─── Tree building ───────────────────────────────────────────────────────────

function getOrCreateFolder(parent: FolderNode, name: string, path: string): FolderNode {
  const existing = parent.childFolders.find((f) => f.path === path);
  if (existing) return existing;
  const folder: FolderNode = { kind: "folder", name, path, childFolders: [], files: [] };
  parent.childFolders.push(folder);
  return folder;
}

function sortFolder(node: FolderNode): void {
  node.childFolders.sort((a, b) => a.name.localeCompare(b.name));
  node.files.sort((a, b) => a.name.localeCompare(b.name));
  for (const child of node.childFolders) sortFolder(child);
}

function buildTree(files: FileSnapshotDTO[]): FolderNode {
  const root: FolderNode = { kind: "folder", name: "", path: "", childFolders: [], files: [] };
  for (const file of files) {
    const parts = file.relativePath.split("/");
    const dirParts = parts.slice(0, -1);
    let current = root;
    let accPath = "";
    for (const segment of dirParts) {
      accPath = accPath ? `${accPath}/${segment}` : segment;
      current = getOrCreateFolder(current, segment, accPath);
    }
    current.files.push(file);
  }
  sortFolder(root);
  return root;
}

function collectFiles(node: FolderNode): FileSnapshotDTO[] {
  const result: FileSnapshotDTO[] = [...node.files];
  for (const child of node.childFolders) result.push(...collectFiles(child));
  return result;
}

function computeStats(node: FolderNode, metricNames: string[]): FolderStats {
  const allFiles = collectFiles(node);
  const totalLines = allFiles.reduce((s, f) => s + f.lineCount, 0);
  const metricCounts: FolderStats["metricCounts"] = {};
  for (const name of metricNames) {
    const counts = { green: 0, amber: 0, red: 0, error: 0, pending: 0, unrun: 0 };
    for (const file of allFiles) {
      const v = file.metrics[name];
      if (v === "pending") counts.pending++;
      else if (v === undefined) counts.unrun++;
      else if (v === null || (typeof v === "object" && v !== null && "error" in v)) counts.error++;
      else if (typeof v === "object" && v !== null && "status" in v) counts[v.status]++;
    }
    metricCounts[name] = counts;
  }
  return { fileCount: allFiles.length, totalLines, metricCounts };
}

// ─── Flat display rows ───────────────────────────────────────────────────────

interface FolderRow {
  kind: "folder";
  node: FolderNode;
  stats: FolderStats;
  depth: number;
  expanded: boolean;
}

interface FileRow {
  kind: "file";
  file: FileSnapshotDTO;
  depth: number;
}

type DisplayRow = FolderRow | FileRow;

function flattenVisible(
  node: FolderNode,
  depth: number,
  expanded: Set<string>,
  metricNames: string[],
  isRoot: boolean
): DisplayRow[] {
  const rows: DisplayRow[] = [];

  if (!isRoot) {
    const stats = computeStats(node, metricNames);
    rows.push({ kind: "folder", node, stats, depth, expanded: expanded.has(node.path) });
    if (!expanded.has(node.path)) return rows;
  }

  for (const child of node.childFolders) {
    rows.push(...flattenVisible(child, isRoot ? 0 : depth + 1, expanded, metricNames, false));
  }
  for (const file of node.files) {
    rows.push({ kind: "file", file, depth: isRoot ? 0 : depth + 1 });
  }
  return rows;
}

// ─── Row ID ──────────────────────────────────────────────────────────────────

function rowId(relativePath: string): string {
  return "insight-row-" + relativePath.replace(/[^a-zA-Z0-9]/g, "-");
}

// ─── Metric count cell ───────────────────────────────────────────────────────

type Counts = FolderStats["metricCounts"][string];

function MetricCountCell({ counts }: { counts: Counts }) {
  const analyzed = counts.green + counts.amber + counts.red + counts.error;
  if (analyzed === 0) {
    return <span className="insight-tree-table__count insight-tree-table__count--unrun">—</span>;
  }
  return (
    <span className="insight-tree-table__counts">
      {counts.red > 0 && (
        <span className="insight-tree-table__count insight-tree-table__count--red">
          {counts.red}
        </span>
      )}
      {counts.amber > 0 && (
        <span className="insight-tree-table__count insight-tree-table__count--amber">
          {counts.amber}
        </span>
      )}
      {counts.green > 0 && (
        <span className="insight-tree-table__count insight-tree-table__count--green">
          {counts.green}
        </span>
      )}
      {counts.error > 0 && (
        <span className="insight-tree-table__count insight-tree-table__count--error">
          {counts.error}
        </span>
      )}
    </span>
  );
}

// ─── Main component ──────────────────────────────────────────────────────────

type Props = {
  files: FileSnapshotDTO[];
  metricLabels: Record<string, string>;
  highlightedPath: string | null;
  selectedPath: string | null;
  onFileSelect: (relativePath: string) => void;
};

export function InsightTreeTable({ files, metricLabels, highlightedPath, selectedPath, onFileSelect }: Props) {
  const [expanded, setExpanded] = useState<Set<string>>(new Set());
  const [flashPath, setFlashPath] = useState<string | null>(null);

  const metricNames = useMemo(() => Object.keys(metricLabels), [metricLabels]);
  const metricEntries = useMemo(() => Object.entries(metricLabels), [metricLabels]);

  const tree = useMemo(() => buildTree(files), [files]);
  const rows = useMemo(
    () => flattenVisible(tree, 0, expanded, metricNames, true),
    [tree, expanded, metricNames]
  );

  // Expand ancestors and scroll when highlightedPath changes
  useEffect(() => {
    if (!highlightedPath) return;
    const parts = highlightedPath.split("/");
    const ancestors = parts
      .slice(0, -1)
      .map((_, i) => parts.slice(0, i + 1).join("/"))
      .filter(Boolean);
    setExpanded((prev) => {
      const next = new Set(prev);
      ancestors.forEach((p) => next.add(p));
      return next;
    });
    setFlashPath(highlightedPath);
    setTimeout(() => {
      document
        .getElementById(rowId(highlightedPath))
        ?.scrollIntoView({ behavior: "smooth", block: "center" });
    }, 50);
    const timer = setTimeout(() => setFlashPath(null), 1800);
    return () => clearTimeout(timer);
  }, [highlightedPath]);

  function toggleFolder(path: string) {
    setExpanded((prev) => {
      const next = new Set(prev);
      if (next.has(path)) next.delete(path);
      else next.add(path);
      return next;
    });
  }

  function collectAllPaths(node: FolderNode): string[] {
    const paths: string[] = [];
    if (node.path) paths.push(node.path);
    for (const child of node.childFolders) paths.push(...collectAllPaths(child));
    return paths;
  }

  function expandAll() {
    setExpanded(new Set(collectAllPaths(tree)));
  }

  function collapseAll() {
    setExpanded(new Set());
  }

  return (
    <div className="insight-tree-table">
      <div className="insight-tree-table__toolbar">
        <button className="insight-tree-table__toolbar-btn" onClick={expandAll}>
          Expand all
        </button>
        <button className="insight-tree-table__toolbar-btn" onClick={collapseAll}>
          Collapse all
        </button>
      </div>

      <div className="insight-tree-table__header">
        <div className="insight-tree-table__col insight-tree-table__col--name">Name</div>
        <div className="insight-tree-table__col insight-tree-table__col--lines">Lines</div>
        {metricEntries.map(([name, label]) => (
          <div key={name} className="insight-tree-table__col insight-tree-table__col--metric">
            {label}
          </div>
        ))}
      </div>

      <div className="insight-tree-table__body">
        {rows.map((row) => {
          if (row.kind === "folder") {
            return (
              <div
                key={row.node.path}
                className="insight-tree-table__folder-row"
                onClick={() => toggleFolder(row.node.path)}
                role="button"
                tabIndex={0}
                onKeyDown={(e) => e.key === "Enter" && toggleFolder(row.node.path)}
              >
                <div
                  className="insight-tree-table__col insight-tree-table__col--name"
                  style={{ "--indent": `${row.depth}rem` } as React.CSSProperties}
                >
                  <span className="insight-tree-table__chevron">
                    {row.expanded ? "▾" : "▸"}
                  </span>
                  <span className="insight-tree-table__folder-name">{row.node.name}/</span>
                  <span className="insight-tree-table__folder-count">
                    {row.stats.fileCount}f
                  </span>
                </div>
                <div className="insight-tree-table__col insight-tree-table__col--lines">
                  {row.stats.totalLines.toLocaleString()}
                </div>
                {metricNames.map((name) => {
                  const counts = row.stats.metricCounts[name];
                  return (
                    <div
                      key={name}
                      className="insight-tree-table__col insight-tree-table__col--metric"
                    >
                      {counts && <MetricCountCell counts={counts} />}
                    </div>
                  );
                })}
              </div>
            );
          }

          const isFlashing = row.file.relativePath === flashPath;
          const isSelected = row.file.relativePath === selectedPath;
          return (
            <div
              key={row.file.relativePath}
              id={rowId(row.file.relativePath)}
              className={`insight-tree-table__file-row${isFlashing ? " insight-tree-table__file-row--flash" : ""}${isSelected ? " insight-tree-table__file-row--selected" : ""}`}
              onClick={() => onFileSelect(row.file.relativePath)}
              role="button"
              tabIndex={0}
              onKeyDown={(e) => e.key === "Enter" && onFileSelect(row.file.relativePath)}
            >
              <div
                className="insight-tree-table__col insight-tree-table__col--name"
                style={{ "--indent": `${row.depth}rem` } as React.CSSProperties}
              >
                <span className="insight-tree-table__file-name">{row.file.name}</span>
              </div>
              <div className="insight-tree-table__col insight-tree-table__col--lines">
                {row.file.lineCount}
              </div>
              {metricEntries.map(([name, label]) => (
                <div
                  key={name}
                  className="insight-tree-table__col insight-tree-table__col--metric"
                >
                  <MetricBadge label={label} value={row.file.metrics[name]} />
                </div>
              ))}
            </div>
          );
        })}
      </div>
    </div>
  );
}
